import ast
import operator

def calculate(expression):
    """
    Calculates the result of a simple arithmetic expression.

    Args:
        expression: A string representing the arithmetic expression.

    Returns:
        The result of the expression as a float, or None if the expression is invalid or unsafe.
    """

    # Define allowed operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.USub: operator.neg
    }

    def eval_expr(node):
        """
        Recursively evaluates a node in the abstract syntax tree.
        """
        if isinstance(node, ast.Num):
            return node.n
        elif isinstance(node, ast.BinOp):
            try:
                return operators[type(node.op)](eval_expr(node.left), eval_expr(node.right))
            except ZeroDivisionError:
                print("Error: Division by zero.")
                return None
        elif isinstance(node, ast.UnaryOp):
            return operators[type(node.op)](eval_expr(node.operand))
        else:
            print(f"Error: Unsupported node type: {type(node)}")
            return None

    try:
        # Parse the expression into an abstract syntax tree (AST)
        node = ast.parse(expression, mode='eval').body

        # Security check:  Only allow numbers and basic operators.  This prevents
        # execution of arbitrary code.  We explicitly check node types.
        for n in ast.walk(node):
            if not isinstance(n, (ast.Num, ast.BinOp, ast.UnaryOp, ast.Name, ast.Expression)):
                print("Error: Invalid expression - only numbers and basic operators are allowed.")
                return None
            if isinstance(n, ast.Name):
                print("Error: Variables are not allowed.")
                return None

        result = eval_expr(node)
        return result

    except (SyntaxError, TypeError) as e:
        print(f"Error: Invalid expression: {e}")
        return None
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return None


if __name__ == "__main__":
