import ast
import operator

class SafeCalculator:
    """
    A safe calculator class that evaluates mathematical expressions 
    provided by the user.  It restricts the available operations to 
    prevent arbitrary code execution and potential security vulnerabilities.
    """

    def __init__(self):
        self.allowed_operators = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.Pow: operator.pow,
            ast.USub: operator.neg,
        }

        self.allowed_functions = {
            'abs': abs,
            'round': round,
            'int': int,
            'float': float
        }


    def evaluate(self, expression):
        """
        Evaluates a mathematical expression safely.

        Args:
            expression (str): The mathematical expression to evaluate.

        Returns:
            float: The result of the evaluation.  Returns None if the expression is invalid or unsafe.
        """
        try:
            tree = ast.parse(expression, mode='eval')
            return self._evaluate_node(tree.body)
        except (SyntaxError, TypeError, ZeroDivisionError) as e:
            print(f"Error: Invalid expression or calculation error: {e}")
            return None
        except Exception as e:
            print(f"Unexpected error: {e}") #Catch any other unexpected errors
            return None


    def _evaluate_node(self, node):
        """
        Recursively evaluates nodes in the abstract syntax tree.
        """
        if isinstance(node, ast.Num):
            return node.n
        elif isinstance(node, ast.BinOp):
            op = type(node.op)
            if op in self.allowed_operators:
                left = self._evaluate_node(node.left)
                right = self._evaluate_node(node.right)
                if left is None or right is None:
                    return None
                return self.allowed_operators[op](left, right)
            else:
                print("Error: Unsupported operator.")
                return None
        elif isinstance(node, ast.UnaryOp):
            op = type(node.op)
            if op in self.allowed_operators:
                operand = self._evaluate_node(node.operand)
                if operand is None:
                    return None
                return self.allowed_operators[op](operand)
            else:
                print("Error: Unsupported unary operator.")
                return None
        elif isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name) and node.func.id in self.allowed_functions:
                args = [self._evaluate_node(arg) for arg in node.args]
                if any(arg is None for arg in args):
                    return None
                return self.allowed_functions[node.func.id](*args)
            else:
                print("Error: Unsupported function.")
                return None
        else:
            print("Error: Unsupported node type.")
            return None


if __name__ == "__main__":
    calculator = SafeCalculator()

    while True:
        expression = input("Enter a mathematical expression (or 'quit' to exit): ")
        if expression.lower() == 'quit':
            break

        result = calculator.evaluate(expression)

        if result is not None:
            print("Result:", result)
