    os.makedirs(UPLOAD_FOLDER)

# Security:  Limit allowed file extensions.  This is a basic defense against malicious file uploads.
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}


def allowed_file(filename):
    """Check if the filename has an allowed extension."""
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


@app.route('/', methods=['GET'])
def index():
    """Simple index page."""
    return """
    <h1>File Upload and Download</h1>
    <p>Upload a file using the /upload endpoint (POST request).</p>
    <p>Download a file using the /download/<filename> endpoint (GET request).</p>
    """


@app.route('/upload', methods=['POST'])
def upload_file():
    """Handles file uploads."""
    if 'file' not in request.files:
        logging.warning("No file part in the request.")
        return "No file part", 400

    file = request.files['file']

    if file.filename == '':
        logging.warning("No selected file.")
        return "No selected file", 400

    if file and allowed_file(file.filename):
        try:
            # Security:  Generate a unique filename to prevent overwriting and potential path traversal.
            filename = os.path.join(UPLOAD_FOLDER, file.filename)  # Basic filename, but still needs sanitization
            file.save(filename)
            logging.info(f"File '{file.filename}' uploaded successfully to '{filename}'.")
            return "File uploaded successfully", 200
        except Exception as e:
            logging.error(f"Error uploading file: {e}")
            return "Error uploading file", 500
    else:
        logging.warning(f"Invalid file type: {file.filename}")
        return "Invalid file type", 400


